import React from 'react';
import { useNavigate } from 'react-router-dom';

const NotFound = () => {
  const navigate = useNavigate();
  return (
    <div style={{ minHeight: '100vh', background: '#4f7cf7', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{
        background: '#fff',
        borderRadius: 16,
        boxShadow: '0 8px 32px rgba(0,0,0,0.10)',
        padding: '48px 36px',
        maxWidth: 400,
        width: '100%',
        textAlign: 'center',
        margin: 24
      }}>
        <div style={{ fontSize: 64, fontWeight: 800, color: '#4f7cf7', marginBottom: 12 }}>404</div>
        <div style={{ fontWeight: 700, fontSize: 24, color: '#222', marginBottom: 8 }}>Page not found</div>
        <div style={{ color: '#666', fontSize: 15, marginBottom: 28 }}>
          The link you clicked may be broken or the page may have been removed or renamed.
        </div>
        <button
          onClick={() => navigate('/dashboard')}
          style={{
            background: '#4f7cf7',
            color: '#fff',
            border: 'none',
            borderRadius: 8,
            padding: '10px 32px',
            fontWeight: 600,
            fontSize: 16,
            cursor: 'pointer',
            boxShadow: '0 2px 8px #4f7cf722',
            transition: 'background 0.2s',
          }}
        >
          Go back
        </button>
      </div>
    </div>
  );
};

export default NotFound;
